    citing_data = json.load(f)

results = []
unique_codes = set()
for rec in citing_data:
    citation_field = rec.get('citation','')
    if not citation_field or citation_field.strip() == '[]':
        continue
    try:
        citations = json.loads(citation_field)
    except Exception:
        # try to find publication numbers with regex as fallback
        citations = []
        for m in re.findall(r"\b[A-Z]{2}-\d{4,}[A-Z0-9\-]*\b", citation_field):
            citations.append({'publication_number': m})
    cites_uc = False
    for c in citations:
        pubnum = c.get('publication_number','').strip()
        if pubnum in uc_pubs:
            cites_uc = True
            break
    if not cites_uc:
        continue
    patinfo = rec.get('Patents_info','')
    # exclude UNIV CALIFORNIA
    if re.search(r'UNIV\W*CALIFORNIA', patinfo, flags=re.IGNORECASE):
        continue
    # extract assignee
    m = re.match(r"^([^\\,\\.]+?)\\s+(?:holds|holds the|has|is assigned to|is assigned|is the assignee|is owned by|owns|belonging to|belongs to|assigned to)", patinfo, flags=re.IGNORECASE)
    if m:
        assignee = m.group(1).strip()
    else:
        # try before 'holds the' anywhere
        m2 = re.search(r"([A-Z0-9 .,&-]{2,}?)\\s+(?:holds|is assigned to|assigned to)", patinfo, flags=re.IGNORECASE)
        if m2:
            assignee = m2.group(1).strip()
        else:
            # fallback: take up to first comma
            assignee = patinfo.split(',')[0].strip()
    # get primary cpc codes
    primary_codes = []
    cpc_field = rec.get('cpc','')
    try:
        cpc_list = json.loads(cpc_field)
    except Exception:
        cpc_list = []
    for entry in cpc_list:
        if isinstance(entry, dict) and entry.get('first'):
            code = entry.get('code')
            if code:
                primary_codes.append(code)
                unique_codes.add(code)
    # if no primary codes, take first code if exists
    if not primary_codes and cpc_list:
        for entry in cpc_list:
            if isinstance(entry, dict) and entry.get('code'):
                primary_codes.append(entry.get('code'))
                unique_codes.add(entry.get('code'))
                break
    if not primary_codes:
        continue
    results.append({'rowid': rec.get('rowid'), 'assignee': assignee, 'primary_codes': primary_codes})

out = {'results': results, 'unique_codes': sorted(unique_codes)}
print('__RESULT__:')
print(json.dumps(out))"}

